// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.hypergraph;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.List;

import org.junit.jupiter.api.Test;

class NodeSetsTest {

	@Test
	void bitAndSingleton() {
		assertEquals(1L, NodeSets.bit(0));
		assertEquals(Long.MIN_VALUE, NodeSets.bit(63));
		assertTrue(NodeSets.isSingleton(NodeSets.bit(63)));
		assertFalse(NodeSets.isSingleton(0L));
		assertFalse(NodeSets.isSingleton(0b11L));
	}

	@Test
	void subsetAndOverlap() {
		assertTrue(NodeSets.isSubset(0b101L, 0b111L));
		assertFalse(NodeSets.isSubset(0b101L, 0b011L));
		assertTrue(NodeSets.isSubset(0L, 0b1L));
		assertTrue(NodeSets.overlaps(0b110L, 0b011L));
		assertFalse(NodeSets.overlaps(0b100L, 0b011L));
	}

	@Test
	void lowestAndHighest() {
		assertEquals(0b010L, NodeSets.lowestBit(0b110L));
		assertEquals(1, NodeSets.lowestIndex(0b110L));
		assertEquals(2, NodeSets.highestIndex(0b110L));
		assertEquals(63, NodeSets.highestIndex(Long.MIN_VALUE));
	}

	@Test
	void nodesBelowInclusive() {
		assertEquals(0b1L, NodeSets.nodesBelowInclusive(0));
		assertEquals(0b111L, NodeSets.nodesBelowInclusive(2));
		assertEquals(-1L, NodeSets.nodesBelowInclusive(63));
	}

	@Test
	void countAndEmpty() {
		assertEquals(0, NodeSets.count(0L));
		assertEquals(3, NodeSets.count(0b10101L));
		assertTrue(NodeSets.isEmpty(0L));
		assertFalse(NodeSets.isEmpty(0b1L));
	}

	@Test
	void nextSubsetEnumeratesAllNonEmptySubsetsAscending() {
		long superset = 0b1101L;
		List<Long> subsets = new ArrayList<>();
		for (long s = NodeSets.nextSubsetOf(0, superset); s != 0; s = NodeSets.nextSubsetOf(s, superset)) {
			subsets.add(s);
		}
		assertEquals(7, subsets.size(), "2^3 - 1 non-empty subsets");
		for (int i = 1; i < subsets.size(); i++) {
			assertTrue(subsets.get(i - 1) < subsets.get(i), "ascending order");
		}
		for (long s : subsets) {
			assertTrue(NodeSets.isSubset(s, superset));
		}
		assertEquals(superset, (long) subsets.get(subsets.size() - 1), "ends with the full set");
	}

	@Test
	void describeListsIndexes() {
		assertEquals("{}", NodeSets.describe(0L));
		assertEquals("{0,2,5}", NodeSets.describe(0b100101L));
	}
}
